            background: `${ext.iconColor ?? "#888"}1c`,
            borderColor: `${ext.iconColor ?? "#888"}33`,
          }}
        >
          {ext.iconEmoji}
        </div>
        <div className="min-w-0 flex-1">
          <div className="flex flex-wrap items-center gap-2">
            <h1 className="serif text-3xl tracking-tight">{name}</h1>
