    <div className="mx-auto max-w-5xl px-6 py-10 animate-pulse">
      {/* Breadcrumb */}
      <div className="mb-6 h-4 w-48 rounded bg-muted" />

      {/* Hero */}
      <div className="flex items-start gap-5 mb-8">
        <div className="h-16 w-16 rounded-xl bg-muted flex-shrink-0" />
